import type { Account } from "./types";
import {
	type CodexUsageSnapshot,
	getWeeklyResetAt,
	isUsageUntouched,
} from "./usage";

export function isAccountAvailable(account: Account, now: number): boolean {
	return !account.quotaExhaustedUntil || account.quotaExhaustedUntil <= now;
}

export function pickRandomAccount(
	accounts: Account[],
	random: () => number = Math.random,
): Account | undefined {
	if (accounts.length === 0) return undefined;
	return accounts[Math.floor(random() * accounts.length)];
}

export function pickEarliestWeeklyResetAccount(
	accounts: Account[],
	usageByEmail: Map<string, CodexUsageSnapshot>,
): Account | undefined {
	const candidates = accounts
		.map((account) => ({
			account,
			resetAt: getWeeklyResetAt(usageByEmail.get(account.email)),
		}))
		.filter(
			(entry): entry is { account: Account; resetAt: number } =>
				typeof entry.resetAt === "number",
		)
		.sort((a, b) => a.resetAt - b.resetAt);

	return candidates[0]?.account;
}

export function pickBestAccount(
	accounts: Account[],
	usageByEmail: Map<string, CodexUsageSnapshot>,
	options?: {
		excludeEmails?: Set<string>;
		now?: number;
		random?: () => number;
	},
): Account | undefined {
	const now = options?.now ?? Date.now();
	const available = accounts.filter(
		(account) =>
			isAccountAvailable(account, now) &&
			!options?.excludeEmails?.has(account.email),
	);
	if (available.length === 0) return undefined;

	const withUsage = available.filter((account) =>
		usageByEmail.has(account.email),
	);
	const untouched = withUsage.filter((account) =>
		isUsageUntouched(usageByEmail.get(account.email)),
	);

	if (untouched.length > 0) {
		return (
			pickEarliestWeeklyResetAccount(untouched, usageByEmail) ??
			pickRandomAccount(untouched, options?.random)
		);
	}

	const earliestWeeklyReset = pickEarliestWeeklyResetAccount(
		withUsage,
		usageByEmail,
	);
	if (earliestWeeklyReset) return earliestWeeklyReset;

	return pickRandomAccount(available, options?.random);
}

export interface CodexUsageWindow {
	usedPercent?: number;
	resetAt?: number;
}

export interface CodexUsageSnapshot {
	primary?: CodexUsageWindow;
	secondary?: CodexUsageWindow;
	fetchedAt: number;
}

interface WhamUsageWindow {
	reset_at?: number;
	used_percent?: number;
}

interface WhamUsageResponse {
	rate_limit?: {
		primary_window?: WhamUsageWindow;
		secondary_window?: WhamUsageWindow;
	};
}

export function normalizeUsedPercent(value?: number): number | undefined {
	if (typeof value !== "number" || !Number.isFinite(value)) return undefined;
	return Math.min(100, Math.max(0, value));
}

export function normalizeResetAt(value?: number): number | undefined {
	if (typeof value !== "number" || !Number.isFinite(value)) return undefined;
	return value * 1000;
}

export function parseUsageWindow(
	window?: WhamUsageWindow,
): CodexUsageWindow | undefined {
	if (!window) return undefined;
	const usedPercent = normalizeUsedPercent(window.used_percent);
	const resetAt = normalizeResetAt(window.reset_at);
	if (usedPercent === undefined && resetAt === undefined) return undefined;
	return { usedPercent, resetAt };
}

export function parseCodexUsageResponse(
	data: WhamUsageResponse,
): Omit<CodexUsageSnapshot, "fetchedAt"> {
	return {
		primary: parseUsageWindow(data.rate_limit?.primary_window),
		secondary: parseUsageWindow(data.rate_limit?.secondary_window),
	};
}

export function isUsageUntouched(usage?: CodexUsageSnapshot): boolean {
	const primary = usage?.primary?.usedPercent;
	const secondary = usage?.secondary?.usedPercent;
	if (primary === undefined || secondary === undefined) return false;
	return primary === 0 && secondary === 0;
}

export function getNextResetAt(usage?: CodexUsageSnapshot): number | undefined {
	const candidates = [
		usage?.primary?.resetAt,
		usage?.secondary?.resetAt,
	].filter((value): value is number => typeof value === "number");
	if (candidates.length === 0) return undefined;
	return Math.min(...candidates);
}

// Weekly reset only (secondary window)
export function getWeeklyResetAt(
	usage?: CodexUsageSnapshot,
): number | undefined {
	const resetAt = usage?.secondary?.resetAt;
	return typeof resetAt === "number" ? resetAt : undefined;
}

import { type CodexUsageSnapshot, parseCodexUsageResponse } from "./usage";

function createLinkedAbortController(signal?: AbortSignal): AbortController {
	const controller = new AbortController();
	if (signal?.aborted) {
		controller.abort();
		return controller;
	}
	signal?.addEventListener("abort", () => controller.abort(), { once: true });
	return controller;
}

function createTimeoutController(
	signal: AbortSignal | undefined,
	timeoutMs: number,
): { controller: AbortController; clear: () => void } {
	const controller = createLinkedAbortController(signal);
	const timeout = setTimeout(() => controller.abort(), timeoutMs);
	return {
		controller,
		clear: () => clearTimeout(timeout),
	};
}

export interface CodexUsageClient {
	fetchCodexUsage(
		accessToken: string,
		accountId?: string,
		options?: { signal?: AbortSignal },
	): Promise<CodexUsageSnapshot>;
}

export function createCodexUsageClient(options?: {
	requestTimeoutMs?: number;
	fetchImpl?: typeof fetch;
}): CodexUsageClient {
	const requestTimeoutMs = options?.requestTimeoutMs ?? 10_000;
	const fetchImpl = options?.fetchImpl ?? fetch;

	return {
		async fetchCodexUsage(
			accessToken: string,
			accountId?: string,
			options?: { signal?: AbortSignal },
		): Promise<CodexUsageSnapshot> {
			const { controller, clear } = createTimeoutController(
				options?.signal,
				requestTimeoutMs,
			);
			try {
				const headers: Record<string, string> = {
					Authorization: `Bearer ${accessToken}`,
					Accept: "application/json",
				};
				if (accountId) {
					headers["ChatGPT-Account-Id"] = accountId;
				}

				const response = await fetchImpl(
					"https://chatgpt.com/backend-api/wham/usage",
					{
						headers,
						signal: controller.signal,
					},
				);

				if (!response.ok) {
					throw new Error(`Usage request failed: ${response.status}`);
				}

				const data = (await response.json()) as Parameters<
					typeof parseCodexUsageResponse
				>[0];
				return { ...parseCodexUsageResponse(data), fetchedAt: Date.now() };
			} finally {
				clear();
			}
		},
	};
}

import type { Account, LegacyStorageData, StorageData } from "./types";

export interface StorageAdapter {
	load(): StorageData;
	save(data: StorageData): void;
}

function isPlainObject(value: unknown): value is Record<string, unknown> {
	return typeof value === "object" && value !== null && !Array.isArray(value);
}

function normalizeAccount(value: unknown): Account | undefined {
	if (!isPlainObject(value)) return undefined;
	const email = typeof value.email === "string" ? value.email : undefined;
	const accessToken =
		typeof value.accessToken === "string" ? value.accessToken : undefined;
	const refreshToken =
		typeof value.refreshToken === "string" ? value.refreshToken : undefined;
	const expiresAt =
		typeof value.expiresAt === "number" && Number.isFinite(value.expiresAt)
			? value.expiresAt
			: undefined;
	if (!email || !accessToken || !refreshToken || expiresAt === undefined) {
		return undefined;
	}

	const account: Account = { email, accessToken, refreshToken, expiresAt };
	if (typeof value.accountId === "string") account.accountId = value.accountId;
	if (typeof value.lastUsed === "number" && Number.isFinite(value.lastUsed)) {
		account.lastUsed = value.lastUsed;
	}
	if (
		typeof value.quotaExhaustedUntil === "number" &&
		Number.isFinite(value.quotaExhaustedUntil)
	) {
		account.quotaExhaustedUntil = value.quotaExhaustedUntil;
	}
	return account;
}

function normalizeAccounts(value: unknown): Account[] {
	if (!Array.isArray(value)) return [];
	return value
		.map(normalizeAccount)
		.filter((entry): entry is Account => !!entry);
}

export function migrateStorageData(raw: unknown): StorageData {
	if (!isPlainObject(raw)) {
		return { schemaVersion: 1, accounts: [] };
	}

	const accounts = normalizeAccounts(raw.accounts);
	const activeEmail =
		typeof raw.activeEmail === "string" ? raw.activeEmail : undefined;

	return {
		schemaVersion: 1,
		accounts,
		...(activeEmail ? { activeEmail } : {}),
	};
}

export function ensureCanonicalStorageData(data: StorageData): StorageData {
	return {
		schemaVersion: 1,
		accounts: data.accounts.map((account) => ({ ...account })),
		...(typeof data.activeEmail === "string"
			? { activeEmail: data.activeEmail }
			: {}),
	};
}

export function isLegacyStorageData(
	value: unknown,
): value is LegacyStorageData {
	return isPlainObject(value) && !("schemaVersion" in value);
}

