export interface ProviderModelDef {
	id: string;
	name: string;
	reasoning: boolean;
	input: ("text" | "image")[];
	cost: {
		input: number;
		output: number;
		cacheRead: number;
		cacheWrite: number;
		total?: number;
	};
	contextWindow: number;
	maxTokens: number;
}

type ApiProviderRef = NonNullable<ReturnType<typeof getApiProvider>>;

type MulticodexProviderConfig = {
	baseUrl: string;
	apiKey: string;
	api: "openai-codex-responses";
	streamSimple: (
		model: Model<Api>,
		context: Context,
		options?: SimpleStreamOptions,
	) => AssistantMessageEventStream;
	models: ProviderModelDef[];
};

export function getOpenAICodexMirror(): {
	baseUrl: string;
	models: ProviderModelDef[];
} {
	const sourceModels = getModels("openai-codex");
	return {
		baseUrl: sourceModels[0]?.baseUrl || "https://chatgpt.com/backend-api",
		models: sourceModels.map((model) => ({
			id: model.id,
			name: model.name,
			reasoning: model.reasoning,
			input: model.input,
			cost: model.cost,
			contextWindow: model.contextWindow,
			maxTokens: model.maxTokens,
		})),
	};
}

export function buildMulticodexProviderConfig(
	accountManager: AccountManager,
): MulticodexProviderConfig | undefined {
	const mirror = getOpenAICodexMirror();
	const baseProvider = getApiProvider("openai-codex-responses") as
		| ApiProviderRef
		| undefined;
	if (!baseProvider) {
		return undefined;
	}
	return {
		baseUrl: mirror.baseUrl,
		apiKey: "managed-by-extension",
		api: "openai-codex-responses",
		streamSimple: createStreamWrapper(accountManager, baseProvider),
		models: mirror.models,
	};
}

import {
	type Api,
	type AssistantMessageEvent,
	type AssistantMessageEventStream,
	type Context,
	createAssistantMessageEventStream,
	type Model,
	type SimpleStreamOptions,
} from "@mariozechner/pi-ai";
import type { AccountManager } from "../../core";
import { isQuotaErrorMessage } from "../../core";
import {
	createErrorAssistantMessage,
	createLinkedAbortController,
	withProvider,
} from "./stream-utils";

const MAX_ROTATION_RETRIES = 5;

export function createStreamWrapper(
	accountManager: AccountManager,
	baseProvider: {
		streamSimple: (
			model: Model<Api>,
			context: Context,
			options?: SimpleStreamOptions,
		) => AsyncIterable<AssistantMessageEvent>;
	},
) {
	return (
		model: Model<Api>,
		context: Context,
		options?: SimpleStreamOptions,
	): AssistantMessageEventStream => {
		const stream = createAssistantMessageEventStream();

		(async () => {
			try {
				const excludedEmails = new Set<string>();
				for (let attempt = 0; attempt <= MAX_ROTATION_RETRIES; attempt++) {
					const now = Date.now();
					const manual = accountManager.getAvailableManualAccount({
						excludeEmails: excludedEmails,
						now,
					});
					const usingManual = Boolean(manual);
					let account = manual;
					if (!account) {
						if (accountManager.hasManualAccount()) {
							accountManager.clearManualAccount();
						}
						account = await accountManager.activateBestAccount({
							excludeEmails: excludedEmails,
							signal: options?.signal,
						});
					}
					if (!account) {
						throw new Error(
							"No available Multicodex accounts. Please use /multicodex-login.",
						);
					}

					const token = await accountManager.ensureValidToken(account);
					const abortController = createLinkedAbortController(options?.signal);

					const internalModel: Model<"openai-codex-responses"> = {
						...(model as Model<"openai-codex-responses">),
						provider: "openai-codex",
						api: "openai-codex-responses",
					};

					const inner = baseProvider.streamSimple(
						{
							...internalModel,
							headers: {
								...(internalModel.headers || {}),
								"X-Multicodex-Account": account.email,
							},
						},
						context,
						{
							...options,
							apiKey: token,
							signal: abortController.signal,
						},
					);

					let forwardedAny = false;
					let retry = false;

					for await (const event of inner) {
						if (event.type === "error") {
							const msg = event.error.errorMessage || "";
							const isQuota = isQuotaErrorMessage(msg);

							if (isQuota && !forwardedAny && attempt < MAX_ROTATION_RETRIES) {
								await accountManager.handleQuotaExceeded(account, {
									signal: options?.signal,
								});
								if (usingManual) {
									accountManager.clearManualAccount();
								}
								excludedEmails.add(account.email);
								abortController.abort();
								retry = true;
								break;
							}

							stream.push(withProvider(event, model.provider));
							stream.end();
							return;
						}

						forwardedAny = true;
						stream.push(withProvider(event, model.provider));

						if (event.type === "done") {
							stream.end();
							return;
						}
					}

					if (retry) {
						continue;
					}

					stream.end();
					return;
				}
			} catch (error) {
				const message =
					error instanceof Error ? error.message : JSON.stringify(error);
				const errorEvent: AssistantMessageEvent = {
					type: "error",
					reason: "error",
					error: createErrorAssistantMessage(
						model,
						`Multicodex failed: ${message}`,
					),
				};
				stream.push(withProvider(errorEvent, model.provider));
				stream.end();
			}
		})();

		return stream;
	};
}

import type {
	ExtensionAPI,
	ExtensionCommandContext,
} from "@mariozechner/pi-coding-agent";
import type { AccountManager } from "../../core";
import { isUsageUntouched } from "../../core";
import { openLoginInBrowser } from "./browser";
import { loginOpenAICodexCompat } from "./oauth";
import { formatResetAt } from "./status";

export function registerMulticodexCommands(
	pi: ExtensionAPI,
	accountManager: AccountManager,
): void {
	pi.registerCommand("multicodex-login", {
		description: "Login to an OpenAI Codex account for the rotation pool",
		handler: async (
			args: string,
			ctx: ExtensionCommandContext,
		): Promise<void> => {
			const email = args.trim();
			if (!email) {
				ctx.ui.notify(
					"Please provide an email/identifier: /multicodex-login my@email.com",
					"error",
				);
				return;
			}

			try {
				ctx.ui.notify(
					`Starting login for ${email}... Check your browser.`,
					"info",
				);

				const creds = await loginOpenAICodexCompat({
					onAuth: ({ url }) => {
						void openLoginInBrowser(pi, ctx, url);
						ctx.ui.notify(`Please open this URL to login: ${url}`, "info");
						console.log(`[multicodex] Login URL: ${url}`);
					},
					onPrompt: async ({ message }) => (await ctx.ui.input(message)) || "",
				});

				accountManager.addOrUpdateAccount(email, {
					access: creds.access,
					refresh: creds.refresh,
					expires: creds.expires,
					...(typeof creds.accountId === "string"
						? { accountId: creds.accountId }
						: {}),
				});
				ctx.ui.notify(`Successfully logged in as ${email}`, "info");
			} catch (error) {
				ctx.ui.notify(
					`Login failed: ${error instanceof Error ? error.message : JSON.stringify(error)}`,
					"error",
				);
			}
		},
	});

	pi.registerCommand("multicodex-use", {
		description: "Switch active Codex account for this session",
		handler: async (
			_args: string,
			ctx: ExtensionCommandContext,
		): Promise<void> => {
			const accounts = accountManager.getAccounts();
			if (accounts.length === 0) {
				ctx.ui.notify(
					"No accounts logged in. Use /multicodex-login first.",
					"warning",
				);
				return;
			}

			const options = accounts.map(
				(account) =>
					account.email +
					(account.quotaExhaustedUntil &&
					account.quotaExhaustedUntil > Date.now()
						? " (Quota)"
						: ""),
			);
			const selected = await ctx.ui.select("Select Account", options);
			if (!selected) return;

			const email = selected.split(" ")[0];
			accountManager.setManualAccount(email);
			ctx.ui.notify(`Switched to ${email}`, "info");
		},
	});

	pi.registerCommand("multicodex-status", {
		description: "Show all Codex accounts and active status",
		handler: async (
			_args: string,
			ctx: ExtensionCommandContext,
		): Promise<void> => {
			await accountManager.refreshUsageForAllAccounts();
			const accounts = accountManager.getAccounts();
			if (accounts.length === 0) {
				ctx.ui.notify(
					"No accounts logged in. Use /multicodex-login first.",
					"warning",
				);
				return;
			}

			const active = accountManager.getActiveAccount();
			const options = accounts.map((account) => {
				const usage = accountManager.getCachedUsage(account.email);
				const isActive = active?.email === account.email;
				const quotaHit =
					account.quotaExhaustedUntil &&
					account.quotaExhaustedUntil > Date.now();
				const untouched = isUsageUntouched(usage) ? "untouched" : null;
				const tags = [
					isActive ? "active" : null,
					quotaHit ? "quota" : null,
					untouched,
				]
					.filter(Boolean)
					.join(", ");
				const suffix = tags ? ` (${tags})` : "";
				const primaryUsed = usage?.primary?.usedPercent;
				const secondaryUsed = usage?.secondary?.usedPercent;
				const primaryReset = usage?.primary?.resetAt;
				const secondaryReset = usage?.secondary?.resetAt;
				const primaryLabel =
					primaryUsed === undefined ? "unknown" : `${Math.round(primaryUsed)}%`;
				const secondaryLabel =
					secondaryUsed === undefined
						? "unknown"
						: `${Math.round(secondaryUsed)}%`;
				const usageSummary = `5h ${primaryLabel} reset:${formatResetAt(primaryReset)} | weekly ${secondaryLabel} reset:${formatResetAt(secondaryReset)}`;
				return `${isActive ? "•" : " "} ${account.email}${suffix} - ${usageSummary}`;
			});

			await ctx.ui.select("MultiCodex Accounts", options);
		},
	});
}

import type {
	ExtensionAPI,
	ExtensionContext,
} from "@mariozechner/pi-coding-agent";
import type { AccountManager } from "../../core";

async function activateBestAccountForSession(
	accountManager: AccountManager,
): Promise<void> {
	await accountManager.refreshUsageForAllAccounts({ force: true });
	const manual = accountManager.getAvailableManualAccount();
	if (manual) return;
	if (accountManager.hasManualAccount()) {
		accountManager.clearManualAccount();
	}
	await accountManager.activateBestAccount();
}

export function registerMulticodexHooks(
	pi: Pick<ExtensionAPI, "on">,
	accountManager: AccountManager,
	lastContextRef: { current?: ExtensionContext },
): void {
	pi.on("session_start", (_event: unknown, ctx: ExtensionContext) => {
		lastContextRef.current = ctx;
		if (accountManager.getAccounts().length === 0) return;
		void activateBestAccountForSession(accountManager);
	});

	pi.on(
		"session_switch",
		(event: { reason?: string }, ctx: ExtensionContext) => {
			lastContextRef.current = ctx;
			if (event.reason === "new") {
				void activateBestAccountForSession(accountManager);
			}
		},
	);
}

import * as fs from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import {
	ensureCanonicalStorageData,
	migrateStorageData,
	type StorageAdapter,
	type StorageData,
} from "../../core";

const STORAGE_FILE = path.join(os.homedir(), ".pi", "agent", "multicodex.json");

export function getMulticodexStoragePath(): string {
	return STORAGE_FILE;
}

export function createPiStorageAdapter(
	storageFile = STORAGE_FILE,
): StorageAdapter {
	return {
		load(): StorageData {
			try {
				if (fs.existsSync(storageFile)) {
					const parsed = JSON.parse(fs.readFileSync(storageFile, "utf-8"));
					const migrated = migrateStorageData(parsed);
					if (JSON.stringify(parsed) !== JSON.stringify(migrated)) {
						const dir = path.dirname(storageFile);
						if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
						fs.writeFileSync(storageFile, JSON.stringify(migrated, null, 2));
					}
					return migrated;
				}
			} catch (error) {
				console.error("Failed to load multicodex accounts:", error);
			}
			return { schemaVersion: 1, accounts: [] };
		},
		save(data: StorageData): void {
			try {
				const dir = path.dirname(storageFile);
				if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
				fs.writeFileSync(
					storageFile,
					JSON.stringify(ensureCanonicalStorageData(data), null, 2),
				);
			} catch (error) {
				console.error("Failed to save multicodex accounts:", error);
			}
		},
	};
}

import type {
	ExtensionAPI,
	ExtensionCommandContext,
} from "@mariozechner/pi-coding-agent";

export async function openLoginInBrowser(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	url: string,
): Promise<void> {
	let command: string;
	let args: string[];

	if (process.platform === "darwin") {
		command = "open";
		args = [url];
	} else if (process.platform === "win32") {
		command = "cmd";
		args = ["/c", "start", "", url];
	} else {
		command = "xdg-open";
		args = [url];
	}

	try {
		await pi.exec(command, args);
	} catch (error) {
		ctx.ui.notify(
			"Could not open a browser automatically. Please open the login URL manually.",
			"warning",
		);
		console.warn("[multicodex] Failed to open browser:", error);
	}
}

import type { OAuthCredentials } from "@mariozechner/pi-ai";
import * as piAi from "@mariozechner/pi-ai";

type LoginOpenAICodexFn = (options: {
	onAuth: (info: { url: string; instructions?: string }) => void;
	onPrompt: (prompt: { message: string }) => Promise<string>;
	onProgress?: (message: string) => void;
	onManualCodeInput?: () => Promise<string>;
	originator?: string;
}) => Promise<OAuthCredentials>;

type RefreshOpenAICodexTokenFn = (
	refreshToken: string,
) => Promise<OAuthCredentials>;

export async function resolveCodexOAuthFns(): Promise<{
	login?: LoginOpenAICodexFn;
	refresh?: RefreshOpenAICodexTokenFn;
}> {
	const topLevelLogin = (piAi as { loginOpenAICodex?: LoginOpenAICodexFn })
		.loginOpenAICodex;
	const topLevelRefresh = (
		piAi as { refreshOpenAICodexToken?: RefreshOpenAICodexTokenFn }
	).refreshOpenAICodexToken;
	if (topLevelLogin && topLevelRefresh) {
		return { login: topLevelLogin, refresh: topLevelRefresh };
	}

	try {
		const oauthModuleId = "@mariozechner/pi-ai/oauth";
		const oauthModule = (await import(oauthModuleId)) as {
			loginOpenAICodex?: LoginOpenAICodexFn;
			refreshOpenAICodexToken?: RefreshOpenAICodexTokenFn;
		};
		return {
			login: oauthModule.loginOpenAICodex,
			refresh: oauthModule.refreshOpenAICodexToken,
		};
	} catch {
		return {};
	}
}

export async function loginOpenAICodexCompat(options: {
	onAuth: (info: { url: string; instructions?: string }) => void;
	onPrompt: (prompt: { message: string }) => Promise<string>;
	onProgress?: (message: string) => void;
	onManualCodeInput?: () => Promise<string>;
	originator?: string;
}): Promise<OAuthCredentials> {
	const { login } = await resolveCodexOAuthFns();
	if (!login) {
		throw new Error(
			"OpenAI Codex OAuth login is unavailable in this pi-ai build.",
		);
	}
	return login(options);
}

export async function refreshOpenAICodexTokenCompat(
	refreshToken: string,
): Promise<OAuthCredentials> {
	const { refresh } = await resolveCodexOAuthFns();
	if (!refresh) {
		throw new Error(
			"OpenAI Codex OAuth token refresh is unavailable in this pi-ai build.",
		);
	}
	return refresh(refreshToken);
}

export function formatResetAt(resetAt?: number): string {
	if (!resetAt) return "unknown";
	const diffMs = resetAt - Date.now();
	if (diffMs <= 0) return "now";
	const diffMinutes = Math.max(1, Math.round(diffMs / 60000));
	if (diffMinutes < 60) return `in ${diffMinutes}m`;
	const diffHours = Math.round(diffMinutes / 60);
	if (diffHours < 48) return `in ${diffHours}h`;
	const diffDays = Math.round(diffHours / 24);
	return `in ${diffDays}d`;
}

import type {
	Api,
	AssistantMessage,
	AssistantMessageEvent,
	Model,
} from "@mariozechner/pi-ai";

export function createErrorAssistantMessage(
	model: Model<Api>,
	message: string,
): AssistantMessage {
	return {
		role: "assistant",
		content: [],
		api: model.api,
		provider: model.provider,
		model: model.id,
		usage: {
			input: 0,
			output: 0,
			cacheRead: 0,
			cacheWrite: 0,
			totalTokens: 0,
			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 },
		},
		stopReason: "error",
		errorMessage: message,
		timestamp: Date.now(),
	};
}

export function createLinkedAbortController(
	signal?: AbortSignal,
): AbortController {
	const controller = new AbortController();
	if (signal?.aborted) {
		controller.abort();
		return controller;
	}
	signal?.addEventListener("abort", () => controller.abort(), { once: true });
	return controller;
}

export function createTimeoutController(
	signal: AbortSignal | undefined,
	timeoutMs: number,
): { controller: AbortController; clear: () => void } {
	const controller = createLinkedAbortController(signal);
	const timeout = setTimeout(() => controller.abort(), timeoutMs);
	return {
		controller,
		clear: () => clearTimeout(timeout),
	};
}

export function withProvider(
	event: AssistantMessageEvent,
	provider: string,
): AssistantMessageEvent {
	if ("partial" in event) {
		return { ...event, partial: { ...event.partial, provider } };
	}
	if (event.type === "done") {
		return { ...event, message: { ...event.message, provider } };
	}
	if (event.type === "error") {
		return { ...event, error: { ...event.error, provider } };
	}
	return event;
}

